import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * ComposedModal is a wrapper for the Carbon ComposedModal component.
 */
export default class ComposedModal extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['ComposedModal'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

ComposedModal.defaultProps = {
    className: '',
};

ComposedModal.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * containerClassName
     */
    containerClassName: PropTypes.any,

    /**
     * danger
     */
    danger: PropTypes.any,

    /**
     * decorator
     */
    decorator: PropTypes.any,

    /**
     * isFullWidth
     */
    isFullWidth: PropTypes.any,

    /**
     * launcherButtonRef
     */
    launcherButtonRef: PropTypes.any,

    /**
     * current
     */
    current: PropTypes.any,

    /**
     * onClose
     */
    onClose: PropTypes.any,

    /**
     * onKeyDown
     */
    onKeyDown: PropTypes.any,

    /**
     * open
     */
    open: PropTypes.any,

    /**
     * preventCloseOnClickOutside
     */
    preventCloseOnClickOutside: PropTypes.any,

    /**
     * selectorPrimaryFocus
     */
    selectorPrimaryFocus: PropTypes.any,

    /**
     * selectorsFloatingMenus
     */
    selectorsFloatingMenus: PropTypes.any,

    /**
     * size
     */
    size: PropTypes.any,

    /**
     * slug
     */
    slug: PropTypes.any,

};
