import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * ToastNotification is a wrapper for the Carbon ToastNotification component.
 */
export default class ToastNotification extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['ToastNotification'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

ToastNotification.defaultProps = {
    className: '',
};

ToastNotification.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * ariaLabel
     */
    ariaLabel: PropTypes.any,

    /**
     * caption
     */
    caption: PropTypes.any,

    /**
     * hideCloseButton
     */
    hideCloseButton: PropTypes.any,

    /**
     * kind
     */
    kind: PropTypes.any,

    /**
     * lowContrast
     */
    lowContrast: PropTypes.any,

    /**
     * onClose
     */
    onClose: PropTypes.any,

    /**
     * onCloseButtonClick
     */
    onCloseButtonClick: PropTypes.any,

    /**
     * role
     */
    role: PropTypes.any,

    /**
     * statusIconDescription
     */
    statusIconDescription: PropTypes.any,

    /**
     * subtitle
     */
    subtitle: PropTypes.any,

    /**
     * timeout
     */
    timeout: PropTypes.any,

    /**
     * title
     */
    title: PropTypes.any,

};
