import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * ContentSwitcher is a wrapper for the Carbon ContentSwitcher component.
 */
export default class ContentSwitcher extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['ContentSwitcher'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

ContentSwitcher.defaultProps = {
    className: '',
};

ContentSwitcher.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * light
     */
    light: PropTypes.any,

    /**
     * lowContrast
     */
    lowContrast: PropTypes.any,

    /**
     * onChange
     */
    onChange: PropTypes.any,

    /**
     * selectedIndex
     */
    selectedIndex: PropTypes.any,

    /**
     * selectionMode
     */
    selectionMode: PropTypes.any,

    /**
     * size
     */
    size: PropTypes.any,

};
