import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * ContainedListItem is a wrapper for the Carbon ContainedListItem component.
 */
export default class ContainedListItem extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['ContainedListItem'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

ContainedListItem.defaultProps = {
    className: '',
};

ContainedListItem.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * action
     */
    action: PropTypes.any,

    /**
     * disabled
     */
    disabled: PropTypes.any,

    /**
     * onClick
     */
    onClick: PropTypes.any,

    /**
     * renderIcon
     */
    renderIcon: PropTypes.any,

};
