import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * TableHeader is a wrapper for the Carbon TableHeader component.
 */
export default class TableHeader extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['TableHeader'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

TableHeader.defaultProps = {
    className: '',
};

TableHeader.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * colSpan
     */
    colSpan: PropTypes.any,

    /**
     * isSortHeader
     */
    isSortHeader: PropTypes.any,

    /**
     * isSortable
     */
    isSortable: PropTypes.any,

    /**
     * onClick
     */
    onClick: PropTypes.any,

    /**
     * scope
     */
    scope: PropTypes.any,

    /**
     * sortDirection
     */
    sortDirection: PropTypes.any,

    /**
     * translateWithId
     */
    translateWithId: PropTypes.any,

};
