import React, { Component } from 'react';
import PropTypes from 'prop-types';
import * as LazyLoader from '../LazyLoader';

/**
 * DefinitionTooltip is a wrapper for the Carbon DefinitionTooltip component.
 */
export default class DefinitionTooltip extends Component {
    render() {
        const {
            className,
            ...otherProps
        } = this.props;

        const RealComponent = LazyLoader['DefinitionTooltip'];
        if (!RealComponent) {
            return null;
        }

        return (
            <React.Suspense fallback={null}>
                <RealComponent 
                    className={className}
                    {...otherProps}
                />
            </React.Suspense>
        );
    }
}

DefinitionTooltip.defaultProps = {
    className: '',
};

DefinitionTooltip.propTypes = {
    /** id */
    id: PropTypes.string,

    /** children */
    children: PropTypes.node,

    /** className */
    className: PropTypes.string,

    /** style */
    style: PropTypes.object,

    /** setProps */
    setProps: PropTypes.func,

    /** loading_state */
    loading_state: PropTypes.shape({ is_loading: PropTypes.bool, prop_name: PropTypes.string, component_name: PropTypes.string }),

    /**
     * align
     */
    align: PropTypes.any,

    /**
     * autoAlign
     */
    autoAlign: PropTypes.any,

    /**
     * defaultOpen
     */
    defaultOpen: PropTypes.any,

    /**
     * definition
     */
    definition: PropTypes.any,

    /**
     * openOnHover
     */
    openOnHover: PropTypes.any,

    /**
     * tooltipText
     */
    tooltipText: PropTypes.any,

    /**
     * triggerClassName
     */
    triggerClassName: PropTypes.any,

};
